import{_ as a,o as l,c as o,ai as t}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"健康检查","description":"","frontmatter":{"read_when":["调试 Mac 应用健康指示器"],"summary":"macOS 应用如何报告 Gateway 网关/Baileys 健康状态","title":"健康检查","x-i18n":{"generated_at":"2026-02-03T07:52:40Z","model":"claude-opus-4-5","provider":"pi","source_hash":"0560e96501ddf53a499f8960cfcf11c2622fcb9056bfd1bcc57876e955cab03d","source_path":"platforms/mac/health.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/health.md","filePath":"zh-CN/platforms/mac/health.md","lastUpdated":1771906665000}'),c={name:"zh-CN/platforms/mac/health.md"};function s(d,e,h,i,r,n){return l(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="macos-上的健康检查" tabindex="-1"><a class="header-anchor" href="#macos-上的健康检查">#</a> macOS 上的健康检查</h1><p>如何从菜单栏应用查看关联渠道是否健康。</p><h2 id="菜单栏" tabindex="-1"><a class="header-anchor" href="#菜单栏">#</a> 菜单栏</h2><ul><li>状态圆点现在反映 Baileys 健康状态： <ul><li>绿色：已关联 + socket 最近已打开。</li><li>橙色：正在连接/重试。</li><li>红色：已登出或探测失败。</li></ul></li><li>第二行显示&quot;linked · auth 12m&quot;或显示失败原因。</li><li>&quot;Run Health Check&quot;菜单项触发按需探测。</li></ul><h2 id="设置" tabindex="-1"><a class="header-anchor" href="#设置">#</a> 设置</h2><ul><li>通用选项卡新增健康卡片，显示：关联认证时间、会话存储路径/数量、上次检查时间、上次错误/状态码，以及运行健康检查/显示日志按钮。</li><li>使用缓存快照，因此 UI 立即加载，离线时优雅降级。</li><li><strong>渠道选项卡</strong>显示渠道状态 + WhatsApp/Telegram 的控制（登录二维码、登出、探测、上次断开/错误）。</li></ul><h2 id="探测工作原理" tabindex="-1"><a class="header-anchor" href="#探测工作原理">#</a> 探测工作原理</h2><ul><li>应用每约 60 秒和按需时通过 <code>ShellExecutor</code> 运行 <code>opensoul health --json</code>。探测加载凭证并报告状态，不发送消息。</li><li>分别缓存上次成功的快照和上次错误以避免闪烁；显示每个的时间戳。</li></ul><h2 id="有疑问时" tabindex="-1"><a class="header-anchor" href="#有疑问时">#</a> 有疑问时</h2><ul><li>你仍然可以使用 <a href="/docs/gateway/health">Gateway 网关健康</a> 中的 CLI 流程（<code>opensoul status</code>、<code>opensoul status --deep</code>、<code>opensoul health --json</code>），并在 <code>/tmp/opensoul/opensoul-*.log</code> 中跟踪 <code>web-heartbeat</code> / <code>web-reconnect</code>。</li></ul>',10)])])}const m=a(c,[["render",s]]);export{p as __pageData,m as default};
